#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int nxt[maxn];
void get_nxt(string s) {
	int n=s.size();
	s=' '+s;
	nxt[1]=0;
	int len=0;
	for(int i=2; i<=n; i++) {
		while(len>0&&s[i]!=s[len+1]) {
			len=nxt[len];
		}
		if(s[i]==s[len+1]) {
			len++;
		}
		nxt[i]=len;
	}
}
vector<int> kmp(string s,string t){
	vector<int> cnt;
	int n=s.size(),m=t.size();
	s=' '+s;
	t=' '+t;
	int len=0;
	for(int i=1; i<=n; i++) {
		while(len==m||(len>0&&s[i]!=t[len+1])) {
			len=nxt[len];
		}
		if(s[i]==t[len+1]) {
			len++;
		}
		if(len==m){
			cnt.push_back(i-m+1);
		}
	}
	return cnt;
}
string s,t;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s>>t;
	get_nxt(t);
	vector<int> e=kmp(s,t);
	for(int s:e){
		cout<<s<<"\n";
	}
	for(int i=1;i<=t.size();i++){
		cout<<nxt[i]<<" ";
	}
	return 0;
}
